var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>관리국 행정부로부터 온 메시지입니다.</color>`,JPN:`<color=#ffd34c>管理局行政府から届いたメッセージです。</color>`,ENG:`<color=#ffd34c>A message has arrived from the Administration Executive.</color>`,TWN:`<color=#ffd34c>以上是來自管理局行政部的訊息。</color>`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`귀사의 적극적인 개입으로 인명 구조작업이 차질 없이 진행될 수 있었습니다.`,JPN:`御社の積極的な介入により、人命救助作業を
滞りなく進めることができました。`,ENG:`Our civilian rescue process was unhindered thanks to your company's active role during this crisis.`,TWN:`多虧貴公司的積極參與，救援行動得以順利進行。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`다행히 과학연구원에서도 유독성 가스에 대한 대응분석을 마쳤다고 합니다.`,JPN:`幸い、科学研究院でも有毒性ガスに関する分析が終わったそうです。`,ENG:`Thankfully, our researchers were successful in performing correspondence analysis on the toxic gas.`,TWN:`萬幸的是科學研究院也完成了有毒性氣體的對應分析。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`구시가지는 길면 1개월 내로 원상복구될 것입니다.`,JPN:`旧市街地は長くても1ヶ月以内に原状復旧されるでしょう。`,ENG:`The old city district will be restored in a month at the latest.`,TWN:`舊城區最晚預計會在1個月內恢復原樣。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`수만 명의 목숨을 구한 데에는 여러분의 공로가 큽니다.`,JPN:`数万人の命を救ったのには、皆様のご尽力のおかげです。`,ENG:`Your distinguished service played a great role in saving thousands of lives.`,TWN:`此次行動拯救了數萬人的生命，貴公司功不可沒。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`다시 한 번 감사드립니다.`,JPN:`もう一度感謝申し上げます。`,ENG:`Thank you again.`,TWN:`對此，我們再次衷心地表示感謝。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};